interface Payable {
    double amountDue();
}
class Invoice implements Payable {
    public double amountDue() { return 25.0; }
}
class Membership implements Payable {
    public double amountDue() { return 10.0; }
}
List<Payable> bills = List.of(new Invoice(), new Membership());
for (Payable bill : bills) System.out.println(bill.amountDue());
